import pytest
import requests
import time

def test_bulk_export_job_state_transitions(bulk_auth_headers, fhir_base_url):
    headers = {
        **bulk_auth_headers,
        "Accept": "application/fhir+json",
        "Prefer": "respond-async",
    }
    kick_resp = requests.get(f"{fhir_base_url}/$export", headers=headers)
    assert kick_resp.status_code == 202, "Kick-off must return 202"
    poll_url = kick_resp.headers["Content-Location"]
    saw_in_progress = False
    for _ in range(30):
        poll_resp = requests.get(poll_url, headers=bulk_auth_headers)
        if poll_resp.status_code == 202:
            saw_in_progress = True
            time.sleep(2)
        elif poll_resp.status_code == 200:
            break
        else:
            pytest.fail(f"Unexpected poll status: {poll_resp.status_code}")
    else:
        pytest.fail("Job did not complete within timeout")
    assert saw_in_progress, "Expected at least one in-progress 202 poll response"
    manifest = poll_resp.json()
    for field in ("transactionTime", "request", "requiresAccessToken", "output"):
        assert field in manifest, f"Manifest missing field: {field}"

